// 1. Extract response
let inputData = $input.first().json;
let rawString = inputData.text || inputData.output || inputData.message || "";

// 2. Clean markdown code fences and parse JSON
let cleanString = rawString.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();

// 3. Try to extract JSON object
let jsonMatch = cleanString.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  cleanString = jsonMatch[0];
}

// 4. Parse and return
let parsed = JSON.parse(cleanString);
return parsed;

const botData = $('Clean AI Output').item.json;
const amount = parseFloat(botData.entities.amount);
const category = botData.entities.category_or_type;
const company = botData.company || "[DEFAULT_COMPANY_NAME]"; 

const debitAccountId = $('Find Expense Account ID').item.json.id;
const creditAccountId = $('Find Cash Account ID').item.json.id;

const fullRef = `${category} ${company}`;
const debitLabel = category;
const creditLabel = `سداد مصروف: ${category}`;

return {
  "ref": fullRef,
  "move_type": "entry",
  "journal_id": 2, // [TEMPLATE: REPLACE WITH YOUR ODOO JOURNAL ID]
  "line_ids": [
    [0, 0, { "account_id": debitAccountId, "name": debitLabel, "debit": amount, "credit": 0.0 }],
    [0, 0, { "account_id": creditAccountId, "name": creditLabel, "debit": 0.0, "credit": amount }]
  ]
};

const partnerId = $('Find Partner ID').item.json.id;
const debitAccountId = $('Find Debit Account ID').item.json.id;
const creditAccountId = $('Find Credit Account ID').item.json.id;

const currencyId = 1; // [TEMPLATE: REPLACE WITH YOUR ODOO CURRENCY ID]

