for (const item of $input.all()) {
  if (item.json.entities && item.json.entities.check_details && item.json.entities.check_details.due_date) {
    const rawDate = item.json.entities.check_details.due_date; 
    const [day, month, year] = rawDate.split('/');
    item.json.entities.check_details.formatted_due_date = `${year}-${month}-${day}`; 
  }
}
return $input.all();

