const input = $input.first().json;
const userMessage = input.user_message || "";
const now = new Date();
let startDate, endDate, displayName;

if (userMessage.includes("شهر") || userMessage.includes("الشهر")) {
  startDate = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  endDate = now.toISOString().split('T')[0];
  displayName = "خلال شهر " + (now.getMonth() + 1);
} else if (userMessage.includes("امبارح")) {
  const yesterday = new Date(now);
  yesterday.setDate(now.getDate() - 1);
  startDate = yesterday.toISOString().split('T')[0];
  endDate = startDate;
  displayName = "امبارح";
} else {
  startDate = now.toISOString().split('T')[0];
  endDate = startDate;
  displayName = "النهاردة";
}

return { startDate, endDate, display_name: displayName };

const items = $input.all();
const aiData = $('Clean AI Output').first().json.entities || {};
const dateData = $('Date Resolver').first().json || {};

let totalDebit = 0; 
let totalCredit = 0; 
let details = "";

let accountName = aiData.source || aiData.category_or_type || "الحساب";
let displayDate = dateData.display_name || "الفترة المحددة";
let actualDate = dateData.startDate || dateData.resolved_date || "";

if (items.length > 0 && items[0].json && items[0].json.account_id) {
  accountName = items[0].json.account_id[1]; 
  for (const item of items) {
    if (!item.json.id) continue;
    const debit = item.json.debit || 0;
    const credit = item.json.credit || 0;
    const ref = item.json.ref || item.json.name || "بدون وصف";

    totalDebit += debit;
    totalCredit += credit;

    if (debit > 0) details += `• مدين/وارد 🟢: ${debit.toLocaleString()} ج ⬅️ (${ref})\n`;
    if (credit > 0) details += `• دائن/منصرف 🔴: ${credit.toLocaleString()} ج ⬅️ (${ref})\n`;
  }
}

let report = `📊 تقرير حساب: ${accountName}\n📅 لـ (${displayDate} - ${actualDate}):\n`;
report += `--------------------------\n`;

if (details) {
    report += details;
    report += `--------------------------\n`;
    if (accountName.includes("شيكات") || accountName.includes("خزين") || accountName.includes("كاش")) {
        report += `💰 إجمالي الوارد (دخل): ${totalDebit.toLocaleString()} جنيه\n`;
        report += `💸 إجمالي المنصرف (خرج): ${totalCredit.toLocaleString()} جنيه\n`;
        report += `⚖️ صافي الحركة: ${(totalDebit - totalCredit).toLocaleString()} جنيه\n`;
    } else {
        report += `💸 إجمالي المصروف: ${totalDebit.toLocaleString()} جنيه\n`;
        if (totalCredit > 0) report += `🔄 إجمالي المرتجعات: ${totalCredit.toLocaleString()} جنيه\n`;
    }
} else {
    report += `⚠️ مفيش أي حركات اتسجلت في الفترة دي.\n`;
}

report += `--------------------------\n`;
report += `💁‍♀️ النظام: الحسبة ظبطت، التقرير معاك!`;

return { json: { report_text: report } };

const items = $input.all();
const supplierName = $('Clean AI Output').first().json.entities.target_name;

let totalDebit = 0; 
let totalCredit = 0; 

items.sort((a, b) => new Date(b.json.date) - new Date(a.json.date));

let details = "";
let counter = 0;

for (const item of items) {
  const debit = item.json.debit || 0;
  const credit = item.json.credit || 0;
  const ref = item.json.name || item.json.ref || "بدون وصف";

  totalDebit += debit;
  totalCredit += credit;

  if (counter < 10) {
    if (credit > 0) details += `🔴 فاتورة/رصيد (+${credit.toLocaleString()} ج) ⬅️ ${ref}\n`;
    else if (debit > 0) details += `🟢 سداد/خصم (-${debit.toLocaleString()} ج) ⬅️ ${ref}\n`;
    counter++;
  }
}

const balance = totalCredit - totalDebit;
let balanceText = "";

if (balance > 0) balanceText = `⚠️ المورد ليه في ذمتنا: ${balance.toLocaleString()} جنيه`;
else if (balance < 0) balanceText = `✅ لينا عند المورد: ${Math.abs(balance).toLocaleString()} جنيه`;
else balanceText = `👌 الحساب مصفر (خالصين)`;

let report = `🧾 كشف حساب مجمع: ${supplierName}\n`;
report += `--------------------------\n`;
report += `أحدث الحركات:\n${details}`;
if (items.length > 10) report += `... (تم إخفاء باقي الحركات القديمة)\n`;
report += `--------------------------\n`;
report += `إجمالي اللي نزل حسابه: ${totalCredit.toLocaleString()} ج\n`;
report += `إجمالي اللي إتدفعـلـه: ${totalDebit.toLocaleString()} ج\n`;
report += `--------------------------\n`;
report += `💰 الصافي النهائي:\n${balanceText}\n`;
report += `--------------------------\n`;
report += `💁‍♀️ النظام: التقرير متقفل، أأمرني باللي بعده!`;

return { json: { report_text: report } };

const aiData = $('Clean AI Output').first().json.entities;
const amount = aiData.amount || 0;
const target = aiData.target_name || aiData.category_or_type || "العملية";

let report = `💁‍♀️ النظام: كله تمام يا ريس! ✅\n`;
report += `تم إثبات وتسجيل (${target}) بمبلغ ${amount.toLocaleString()} جنيه في الدفاتر بنجاح!`;

return { json: { report_text: report } };
